const STROKES=['Free','Back','Breast','Fly','IM'];
function gStroke(e){for(const s of STROKES)if(e.includes(s))return s;return 'Other';}

function t2s(t){
  if(t===null||t===undefined)return null;
  const s=String(t).trim();
  if(!s||s==='null'||s==='None')return null;
  const f=parseFloat(s);
  if(!isNaN(f)&&!s.includes(':'))return f;
  const m=s.match(/^(\d+):(\d+(?:\.\d+)?)$/);
  if(m)return parseInt(m[1])*60+parseFloat(m[2]);
  return null;
}

let S={athletes:[],standards:[],teamName:'OCA',teamLogo:null,theme:'dark'};
let curPage='roster',gFilt='all',chartG='female',stdVG='female';
let editAthId=null,editTimesId=null,teStroke='Free',lbG='all',evST='All';

// dc(), setState(), genAthleteId(), validateTime() live in state.js

function loadState(){
  try{
    const d=localStorage.getItem('swimApp_v3');
    if(d){const p=JSON.parse(d);S.athletes=p.athletes||dc(DEFAULT_ATHLETES);S.standards=p.standards||dc(DEFAULT_STANDARDS);S.teamName=p.teamName||'OCA';S.teamLogo=p.teamLogo||null;S.accentColor=p.accentColor||null;}
    else{S.athletes=dc(DEFAULT_ATHLETES);S.standards=dc(DEFAULT_STANDARDS);}
  }catch(e){S.athletes=dc(DEFAULT_ATHLETES);S.standards=dc(DEFAULT_STANDARDS);}
  if(S.theme==='light'){document.body.classList.add('light-mode');}
  else{document.body.classList.remove('light-mode');}
  if(S.accentColor)applyAccentColor(S.accentColor,false);
}

function applyAccentColor(color,save_){
  document.documentElement.style.setProperty('--acc',color);
  S.accentColor=color;
  if(save_!==false)save();
  // Update active swatch
  document.querySelectorAll('.accent-swatch').forEach(s=>{
    s.classList.toggle('active',s.dataset.color===color);
  });
}
function save(){
  try{
    localStorage.setItem('swimApp_v3',JSON.stringify({
      athletes:S.athletes,standards:S.standards,teamName:S.teamName,
      teamLogo:S.teamLogo,theme:S.theme,accentColor:S.accentColor||null,
      meets:S.meets||[],attendance:S.attendance||[]
    }));
  }catch(e){}
}

// ── CUT LOGIC ────────────────────────────────────────────────
function getBestCut(a,ev){
  const t=a.times[ev];if(!t)return null;
  const ts=t2s(t);if(ts===null)return null;
  const tk=a.gender==='female'?'timesF':'timesM';
  let best=null;
  const sorted=[...S.standards].sort((a,b)=>a.priority-b.priority);
  for(const std of sorted){
    const sv=std[tk][ev];if(!sv)continue;
    const ss=t2s(sv);if(ss===null)continue;
    if(ts<=ss)best=std;
  }
  return best;
}

function getStats(a){
  const cuts={},byStd={};
  S.standards.forEach(s=>byStd[s.id]=0);
  for(const ev of EVENTS){
    // Count cuts per standard independently — no subsumption
    const tk=a.gender==='female'?'timesF':'timesM';
    const ats=t2s(a.times[ev]);
    if(ats===null) continue;
    S.standards.forEach(s=>{
      const sv=s[tk][ev]; if(!sv) return;
      const ss=t2s(sv); if(ss===null) return;
      if(ats<=ss) byStd[s.id]++;
    });
    // cuts{} still tracks the BEST (highest priority) cut per event for coloring
    const c=getBestCut(a,ev);
    if(c) cuts[ev]=c;
  }
  // total = sum of every cut achieved across every standard
  const total=Object.values(byStd).reduce((s,n)=>s+n,0);
  return{cuts,byStd,total};
}

function badges(stats,large){
  return S.standards.map(std=>{
    const n=stats.byStd[std.id]||0,has=n>0;
    const bgN=has?std.color:'rgba(255,255,255,0.06)';
    const bgL=has?std.color+'22':'rgba(255,255,255,0.03)';
    const cN=has?'#fff':'rgba(255,255,255,0.2)';
    const cL=has?std.color:'rgba(255,255,255,0.18)';
    const bdr=has?std.color+'55':'rgba(255,255,255,0.06)';
    const fN=large?'18px':'14px',pN=large?'5px 8px 5px 10px':'4px 7px 4px 8px';
    const fL=large?'11px':'10px',pL=large?'5px 10px 5px 6px':'4px 8px 4px 5px';
    return `<span class="sb" style="border-color:${bdr}"><span class="sbc" style="background:${bgN};color:${cN};font-size:${fN};padding:${pN}">${n}</span><span class="sbn" style="background:${bgL};color:${cL};font-size:${fL};padding:${pL}">${std.name}</span></span>`;
  }).join('');
}

// ── ROSTER ───────────────────────────────────────────────────
function renderRoster(){
  const q=document.getElementById('srch').value.toLowerCase();
  const list=document.getElementById('rosterList');
  const aths=S.athletes.filter(a=>{
    if(gFilt==='male'&&a.gender!=='male')return false;
    if(gFilt==='female'&&a.gender!=='female')return false;
    return !q||a.name.toLowerCase().includes(q);
  });
  if(!aths.length){list.innerHTML='<div class="nd"><div class="ndi">🏊</div>No athletes found</div>';return;}
  list.innerHTML=aths.map(a=>{
    const st=getStats(a);
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    const allCuts=Object.entries(st.cuts);

    // Build a map of event -> all standards the athlete qualifies for (not just best)
    const tk=a.gender==='female'?'timesF':'timesM';
    const evAllStds={};
    for(const ev of EVENTS){
      const ats=t2s(a.times[ev]); if(ats===null) continue;
      const qualified=S.standards.filter(s=>{
        const sv=s[tk][ev]; if(!sv) return false;
        const ss=t2s(sv); if(ss===null) return false;
        return ats<=ss;
      }).map(s=>s.id);
      if(qualified.length) evAllStds[ev]=qualified;
    }

    // Event pills — hidden by default, revealed when a badge is tapped
    // data-std = best cut (for color), data-stds = all qualified standards (for filtering)
    const pillsHtml=allCuts.map(([ev,std])=>{
      const allStdIds=(evAllStds[ev]||[std.id]).join(',');
      return `<span class="cut-pill" style="background:${std.color}22;border:1.5px solid ${std.color}55;color:${std.color}" data-std="${std.id}" data-stds="${allStdIds}">${ev}</span>`;
    }).join('');

    // ONE row: the split-badge chips ARE the toggle buttons.
    // Standards with cuts = clickable button. Standards with 0 = muted non-button.
    const badgeRowHtml=S.standards.map(std=>{
      const n=st.byStd[std.id]||0;
      if(!n){
        return `<span class="sb" style="border-color:rgba(255,255,255,.07);opacity:.3;pointer-events:none;">
          <span class="sbc" style="background:rgba(255,255,255,.05);color:var(--muted);font-size:14px;padding:4px 7px 4px 8px;">0</span>
          <span class="sbn" style="background:rgba(255,255,255,.02);color:var(--muted);font-size:10px;padding:4px 8px 4px 5px;">${std.name}</span>
        </span>`;
      }
      return `<button class="sb-toggle" data-std-id="${std.id}"
          onclick="event.stopPropagation();toggleBadgePills(this,'${a.id}','${std.id}')"
          style="display:inline-flex;align-items:stretch;border-radius:7px;overflow:hidden;border:1.5px solid ${std.color}44;background:transparent;cursor:pointer;padding:0;font-family:var(--font);transition:all .18s;">
          <span class="sbc" style="background:${std.color};color:#fff;font-size:14px;padding:4px 7px 4px 8px;font-weight:800;display:flex;align-items:center;justify-content:center;min-width:26px;">${n}</span>
          <span class="sbn" style="background:${std.color}22;color:${std.color};font-size:10px;padding:4px 8px 4px 5px;font-weight:700;text-transform:uppercase;letter-spacing:.3px;display:flex;align-items:center;">${std.name}</span>
        </button>`;
    }).join('');

    return `<div class="ac ${a.gender}" onclick="showProfile('${a.id}')">
      <div class="ahdr">
        <div class="av ${a.gender}">${ini}</div>
        <div style="flex:1;min-width:0;">
          <div class="aname">${a.name}</div>
          <div class="ameta">${a.gender==='female'?'♀':'♂'}${a.age?' · '+a.age:''} · ${Object.keys(a.times).length} events</div>
        </div>
        <button class="btn bsm bs" onclick="event.stopPropagation();openEditAth('${a.id}')" style="flex-shrink:0">✏️</button>
      </div>
      <div class="brow" style="gap:5px;flex-wrap:wrap;margin-top:7px;">${badgeRowHtml}</div>
      ${allCuts.length?`<div class="cut-pills-row" data-pills data-ath="${a.id}">${pillsHtml}</div>`:''}
      <!-- Summary pill — always visible at bottom of card -->
      <div class="cut-summary-row" id="cutSummary_${a.id}">
        <span class="cut-summary-pill">
          <span class="csp-medal">🏅</span>
          <span class="csp-total" id="cspTotal_${a.id}">${st.total}</span>
          <span class="csp-label">cuts</span>
        </span>
      </div>
    </div>`;
  }).join('');
}

// toggleBadgePills:
//   - Tap active badge → collapse pills (toggle off)
//   - Tap different badge → swap to that standard's pills
function toggleBadgePills(btn, athId, stdId){
  const card=btn.closest('.ac');
  if(!card)return;
  const pillsRow=card.querySelector('[data-pills]');
  const allBadges=card.querySelectorAll('.sb-toggle');
  const isAlreadyActive=btn.classList.contains('sb-active');

  // Reset ALL badges to their default un-pressed look
  allBadges.forEach(b=>{
    b.classList.remove('sb-active');
    const sid=b.dataset.stdId;
    const std=S.standards.find(s=>s.id===sid);
    if(!std)return;
    const sbc=b.querySelector('.sbc');
    const sbn=b.querySelector('.sbn');
    if(sbc){sbc.style.background=std.color;sbc.style.color='#fff';}
    if(sbn){sbn.style.background=std.color+'22';sbn.style.color=std.color;}
    b.style.borderColor=std.color+'44';
    b.style.boxShadow='none';
    b.style.transform='none';
  });

  // Close pills row
  if(pillsRow)pillsRow.classList.remove('open');

  // If was already active, just collapse — reset summary too
  if(isAlreadyActive){
    const athId3 = card.querySelector('[data-pills]')?.dataset.ath;
    if(athId3) updateCutSummaryPill(athId3, null);
    return;
  }

  // Activate this badge with "pressed" visual
  const activeStd=S.standards.find(s=>s.id===stdId);
  if(!activeStd)return;
  btn.classList.add('sb-active');
  const sbc=btn.querySelector('.sbc');
  const sbn=btn.querySelector('.sbn');
  if(sbc){sbc.style.background='rgba(0,0,0,.3)';sbc.style.color='#fff';}
  if(sbn){sbn.style.background=activeStd.color;sbn.style.color='#fff';}
  btn.style.borderColor=activeStd.color;
  btn.style.boxShadow=`inset 0 2px 5px rgba(0,0,0,.4), 0 0 0 1px ${activeStd.color}`;
  btn.style.transform='scale(.97)';

  // Show only pills for this standard
  if(pillsRow){
    pillsRow.classList.add('open');
    pillsRow.querySelectorAll('.cut-pill').forEach(pill=>{
      const qualifiedStds=(pill.dataset.stds||pill.dataset.std).split(',');
      const visible=qualifiedStds.includes(stdId);
      pill.style.display=visible?'':'none';
      if(visible){
        pill.style.background=activeStd.color+'22';
        pill.style.borderColor=activeStd.color+'55';
        pill.style.color=activeStd.color;
      } else {
        const origStd=S.standards.find(s=>s.id===pill.dataset.std);
        if(origStd){
          pill.style.background=origStd.color+'22';
          pill.style.borderColor=origStd.color+'55';
          pill.style.color=origStd.color;
        }
      }
    });
  }

  // Update the summary pill to show fraction: total / stdCount in std color
  const athId2 = card.querySelector('[data-pills]')?.dataset.ath;
  if(athId2) updateCutSummaryPill(athId2, stdId);
}

function updateCutSummaryPill(athId, activeStdId){
  const summaryEl = document.getElementById('cutSummary_' + athId);
  if(!summaryEl) return;
  const a = S.athletes.find(x => x.id === athId);
  if(!a) return;
  const st = getStats(a);
  const total = st.total;

  if(!activeStdId){
    // No filter — show total only
    summaryEl.innerHTML = `<span class="cut-summary-pill">
      <span class="csp-medal">🏅</span>
      <span class="csp-total">${total}</span>
      <span class="csp-label">cuts</span>
    </span>`;
    return;
  }

  const std = S.standards.find(s => s.id === activeStdId);
  if(!std) return;
  const stdCount = st.byStd[activeStdId] || 0;

  summaryEl.innerHTML = `<span class="cut-summary-pill">
    <span class="csp-medal">🏅</span>
    <span class="csp-total">${total}</span>
    <span class="csp-slash">/</span>
    <span class="csp-std-count" style="color:${std.color};text-shadow:0 0 8px ${std.color}66;">${stdCount}</span>
    <span class="csp-std-label" style="color:${std.color};">${std.name}</span>
  </span>`;
}

// ── PROFILE ──────────────────────────────────────────────────
function showProfile(id){
  const a=S.athletes.find(x=>x.id===id);if(!a)return;
  // Use roadmap-aware builder if available, else fall back
  if(typeof buildRoadmapProfileContent==='function'){
    initProfileRoadmap(id);
    document.getElementById('profileContent').innerHTML=buildRoadmapProfileContent(a);
    document.getElementById('profileContent').dataset.athleteId=id;
  } else {
    const st=getStats(a);
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    let timesHtml='';
    for(const stroke of STROKES){
      const evs=EVENTS.filter(e=>gStroke(e)===stroke&&a.times[e]);if(!evs.length)continue;
      timesHtml+=`<div style="margin-bottom:13px;"><div class="ctitle">${stroke}</div><div class="tgrid">${evs.map(ev=>{
        const t=a.times[ev];const c=getBestCut(a,ev);
        return `<div class="tcell" style="background:${c?c.color+'22':'var(--sur2)'};border-color:${c?c.color:'var(--bdr)'}"><div class="tev">${ev}</div><div class="tval">${t}</div>${c?`<div class="tstd" style="color:${c.color}">● ${c.name}</div>`:''}</div>`;
      }).join('')}</div></div>`;
    }
    document.getElementById('profileContent').innerHTML=`
      <div class="phdr">
        <div class="pav ${a.gender}">${ini}</div>
        <div style="flex:2;min-width:0;"><div class="pname">${a.name}</div><div style="font-size:12px;color:var(--muted);margin-bottom:8px;">${a.gender==='female'?'♀ Female':'♂ Male'}${a.age?' · '+a.age:''} · ${Object.keys(a.times).length} events</div><div class="brow">${badges(st,true)}</div></div>
      </div>
      <div style="display:flex;gap:7px;flex-wrap:wrap;margin-bottom:13px;">
        <button class="btn bsm bp" onclick="openEditTimes('${id}')">Edit Times</button>
        <button class="btn bsm bs" onclick="openEditAth('${id}')">Edit Info</button>
        <button class="btn bsm bd" onclick="delAth('${id}')">Delete</button>
      </div>
      ${timesHtml||'<div style="color:var(--muted);font-size:13px;padding:20px 0;text-align:center;">No times recorded yet</div>'}`;
  }
  showPage('profile');
}

// ── CHART ────────────────────────────────────────────────────
let _chartSelectedAths=[];  // empty = show all

function renderChart(){
  const cgBtn=document.getElementById('cgBtn');
  if(cgBtn)cgBtn.textContent=chartG==='female'?'Women':chartG==='male'?'Men':'All';

  // Build athlete pool
  let pool=S.athletes.filter(a=>chartG==='all'?true:a.gender===chartG);
  // Sort pool alphabetically by last name
  pool=[...pool].sort((a,b)=>{
    const la=a.name.split(' ').slice(-1)[0],lb=b.name.split(' ').slice(-1)[0];
    return la.localeCompare(lb);
  });
  // Apply selection filter if active
  const filtered=_chartSelectedAths.length>0?pool.filter(a=>_chartSelectedAths.includes(a.id)):pool;

  // Update selector button label
  const trigEl=document.getElementById('athSelTrigger');
  if(trigEl){
    if(_chartSelectedAths.length>0){
      trigEl.textContent=_chartSelectedAths.length+' selected ▾';
      trigEl.classList.add('has-selection');
    } else {
      trigEl.textContent='Select Athletes ▾';
      trigEl.classList.remove('has-selection');
    }
  }
  const allBtn=document.getElementById('athSelAllBtn');
  if(allBtn){
    if(_chartSelectedAths.length===0){allBtn.classList.remove('inactive');}
    else{allBtn.classList.add('inactive');}
  }

  // Build vertical table: events = rows, athletes = columns
  // Group events by stroke
  const tbl=document.getElementById('rctTbl');
  if(!tbl)return;

  let html='<thead><tr><th style="text-align:left;padding:5px 10px;font-size:10px;color:var(--muted);font-weight:700;min-width:130px;">Event</th>';
  filtered.forEach(a=>{
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    const last=a.name.split(' ').slice(-1)[0];
    html+=`<th class="ath-col-hdr" onclick="showProfile('${a.id}')" title="${a.name}">${last}<br><span style="font-size:9px;font-weight:500;opacity:.7;">${ini}</span></th>`;
  });
  html+='</tr></thead><tbody>';

  STROKES.forEach(stroke=>{
    const evs=EVENTS.filter(e=>gStroke(e)===stroke&&filtered.some(a=>a.times[e]));
    if(!evs.length)return;
    html+=`<tr class="stroke-header"><td colspan="${filtered.length+1}">${stroke}</td></tr>`;
    evs.forEach(ev=>{
      html+=`<tr><td>${ev}</td>`;
      filtered.forEach(a=>{
        const t=a.times[ev];const c=t?getBestCut(a,ev):null;
        html+=`<td style="${c?`background:${c.color}33;color:${c.color};font-weight:700;`:''}">${t||'<span style="color:rgba(255,255,255,.1);font-size:10px;">—</span>'}</td>`;
      });
      html+='</tr>';
    });
  });

  tbl.innerHTML=html+'</tbody>';
  tbl.className='chart-vert-tbl';

  renderAthSelectorDropdown(pool);
}

function renderAthSelectorDropdown(pool){
  const dd=document.getElementById('athSelDropdown');
  if(!dd)return;
  dd.innerHTML=pool.map(a=>{
    const sel=_chartSelectedAths.includes(a.id);
    return `<div class="ath-sel-item ${sel?'selected':''}" onclick="toggleAthSel('${a.id}')">
      <div class="ath-sel-check">${sel?'✓':''}</div>
      <div class="av ${a.gender}" style="width:24px;height:24px;font-size:9px;flex-shrink:0;">
        ${a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase()}
      </div>
      <span>${a.name}</span>
    </div>`;
  }).join('')+
  (_chartSelectedAths.length>0?`<div class="ath-sel-reset" onclick="resetAthSel()">✕ Reset Selection</div>`:'');
}

function toggleAthSel(id){
  const idx=_chartSelectedAths.indexOf(id);
  if(idx>-1)_chartSelectedAths.splice(idx,1);
  else _chartSelectedAths.push(id);
  renderChart();
}
function resetAthSel(){_chartSelectedAths=[];renderChart();}
function toggleAthSelDropdown(){
  const dd=document.getElementById('athSelDropdown');
  if(dd)dd.classList.toggle('open');
}

// ── OVERVIEW ─────────────────────────────────────────────────
function renderOverview(){
  const tot=S.athletes.reduce((s,a)=>s+getStats(a).total,0);
  document.getElementById('ovStats').innerHTML=`
    <div class="scard"><div class="snum">${S.athletes.length}</div><div class="slbl">Athletes</div></div>
    <div class="scard"><div class="snum">${tot}</div><div class="slbl">Total Cuts</div></div>
    <div class="scard"><div class="snum">${S.athletes.filter(a=>a.gender==='male').length}</div><div class="slbl">Men</div></div>
    <div class="scard"><div class="snum">${S.athletes.filter(a=>a.gender==='female').length}</div><div class="slbl">Women</div></div>`;
  renderCutFilterPills();
  renderLB();renderEvChart();renderStrokeChart();renderStdBarChart();
  // Bubble widget (defined in bubble_threshold_fix.js)
  if(typeof renderBubbleThresholdNote==='function') renderBubbleThresholdNote();
  if(typeof renderBubbleWidget==='function') renderBubbleWidget(bubbleGender);
}

function renderCutFilterPills(){
  const container=document.getElementById('cutFilterPills');
  if(!container)return;
  const pills=[{id:'all',name:'All',color:'var(--acc)'},...S.standards.sort((a,b)=>a.priority-b.priority)];
  container.innerHTML=pills.map(p=>`
    <button class="cfp-btn ${p.id===lbStdFilter?'active':''}"
      onclick="setCutFilter('${p.id}')"
      style="${p.id!=='all'?`--cfp-color:${p.color};`:''}${p.id===lbStdFilter&&p.id!=='all'?`background:${p.color};border-color:${p.color};`:''}">
      ${p.name}
    </button>`).join('');
}

let lbStdFilter='all';
function setCutFilter(id){
  lbStdFilter=id;
  renderCutFilterPills();
  renderLB();
}

let bubbleGender = 'all';
function setBubbleG(g) {
  bubbleGender = g;
  ['All','M','F'].forEach(x => document.getElementById('bbg'+x).className='gbtn');
  document.getElementById('bbg'+{all:'All',male:'M',female:'F'}[g]).className='gbtn '+ {all:'aa',male:'am',female:'af'}[g];
  renderBubbleThresholdNote();
  renderBubbleWidget(g);
}
function renderBubbleThresholdNote() {
  const el = document.getElementById('bubbleThresholdNote');
  if (el) el.textContent = 'Thresholds: 50s < 0.8s · 100s < 1.5s · 200s < 3.0s · 500s < 5.0s · 1000s < 8.0s · 1650s < 12.0s';
}

function renderLB(){
  const sid=lbStdFilter||'all';
  function score(a){const st=getStats(a);return sid==='all'?st.total:(st.byStd[sid]||0);}
  function makeRow(a,i,compact){
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    const cnt=score(a);
    const medal=i===0?'🥇':i===1?'🥈':i===2?'🥉':(i+1);
    return `<div class="lbr" onclick="showProfile('${a.id}')">
      <div class="lbrk ${i<3?'t3':''}">${medal}</div>
      <div class="av ${a.gender}" style="width:26px;height:26px;font-size:10px;">${ini}</div>
      <div class="lbn">${a.name}</div>
      <div class="lbc">${cnt}</div>
    </div>`;
  }
  const lbEl=document.getElementById('leaderboard');
  if(!lbEl)return;
  // Women panel
  const womenRanked=S.athletes.filter(a=>a.gender==='female').map(a=>({...a,cnt:score(a)})).filter(a=>a.cnt>0).sort((a,b)=>b.cnt-a.cnt);
  // Men panel
  const menRanked=S.athletes.filter(a=>a.gender==='male').map(a=>({...a,cnt:score(a)})).filter(a=>a.cnt>0).sort((a,b)=>b.cnt-a.cnt);
  // Combined top 10
  const allRanked=S.athletes.map(a=>({...a,cnt:score(a)})).filter(a=>a.cnt>0).sort((a,b)=>b.cnt-a.cnt).slice(0,10);
  const empty='<div style="color:var(--muted);padding:10px 12px;font-size:12px;text-align:center;">No data</div>';
  lbEl.innerHTML=`<div class="lb-three-col">
    <div class="lb-panel">
      <div class="lb-panel-hdr women">♀ Women</div>
      <div class="lb-panel-body">${womenRanked.length?womenRanked.map((a,i)=>makeRow(a,i)).join(''):empty}</div>
    </div>
    <div class="lb-panel">
      <div class="lb-panel-hdr men">♂ Men</div>
      <div class="lb-panel-body">${menRanked.length?menRanked.map((a,i)=>makeRow(a,i)).join(''):empty}</div>
    </div>
    <div class="lb-panel">
      <div class="lb-panel-hdr combined">⭐ Combined Top 10</div>
      <div class="lb-panel-body">${allRanked.length?allRanked.map((a,i)=>makeRow(a,i)).join(''):empty}</div>
    </div>
  </div>`;
}

let evStdFilter='all';
function renderEvChart(){
  const wrap=document.getElementById('evStrokeTabs');
  // Always rebuild tabs so standard pills reflect current S.standards
  wrap.innerHTML='';

  // Row 1: stroke filter
  const strokeRow=document.createElement('div');
  strokeRow.style.cssText='display:flex;flex-wrap:wrap;gap:4px;margin-bottom:5px;';
  ['All',...STROKES].forEach(s=>{
    const b=document.createElement('button');
    b.className='stab'+(s===evST?' active':'');
    b.textContent=s;
    b.onclick=()=>{
      evST=s;
      strokeRow.querySelectorAll('.stab').forEach(x=>x.classList.remove('active'));
      b.classList.add('active');
      buildEvChart();
    };
    strokeRow.appendChild(b);
  });
  wrap.appendChild(strokeRow);

  // Row 2: standard filter pills
  const stdRow=document.createElement('div');
  stdRow.style.cssText='display:flex;flex-wrap:wrap;gap:4px;margin-bottom:2px;';
  [{id:'all',name:'All',color:'var(--acc)'},...[...S.standards].sort((a,b)=>a.priority-b.priority)].forEach(std=>{
    const active=std.id===evStdFilter;
    const b=document.createElement('button');
    b.className='stab evstd-pill'+(active?' active':'');
    b.textContent=std.name;
    b.style.cssText=`font-size:9px;padding:2px 8px;${active&&std.id!=='all'?`background:${std.color};border-color:${std.color};color:#fff;`:`border-color:${std.id!=='all'?std.color+'66':'var(--bdr)'};color:${std.id!=='all'?std.color:'var(--muted)'};`}`;
    b.onclick=()=>{
      evStdFilter=std.id;
      stdRow.querySelectorAll('.evstd-pill').forEach(x=>{
        x.classList.remove('active');
        x.style.background='';
        const xstd=S.standards.find(s=>s.id===x.dataset.sid);
        if(xstd){x.style.borderColor=xstd.color+'66';x.style.color=xstd.color;}
        else{x.style.borderColor='var(--bdr)';x.style.color='var(--muted)';}
      });
      b.classList.add('active');
      if(std.id!=='all'){b.style.background=std.color;b.style.borderColor=std.color;b.style.color='#fff';}
      buildEvChart();
    };
    b.dataset.sid=std.id;
    stdRow.appendChild(b);
  });
  wrap.appendChild(stdRow);

  buildEvChart();
}
function buildEvChart(){
  const evs=EVENTS.filter(e=>evST==='All'||gStroke(e)===evST);
  const std=evStdFilter!=='all'?S.standards.find(s=>s.id===evStdFilter):null;
  const data=evs.map(ev=>{
    let n;
    if(std){
      const tk=std.timesF; // count athletes who have a cut in this specific standard for this event
      n=S.athletes.filter(a=>{
        const ats=t2s(a.times[ev]); if(ats===null) return false;
        const tk2=a.gender==='female'?'timesF':'timesM';
        const cv=std[tk2][ev]; if(!cv) return false;
        return ats<=t2s(cv);
      }).length;
    } else {
      n=S.athletes.filter(a=>getBestCut(a,ev)!==null).length;
    }
    return{ev,n};
  }).sort((a,b)=>b.n-a.n).filter(d=>d.n>0);
  if(!data.length){document.getElementById('evChart').innerHTML='<div style="color:var(--muted);font-size:12px;padding:8px 0;">No data</div>';return;}
  const numColor=std?std.color:'var(--acc)';
  const rows=data.map((d,i)=>{
    const top=i<3;
    const medals=['🥇','🥈','🥉'];
    return `<tr class="ovt-row${top?' ovt-top':''}">
      <td class="ovt-rank">${top?medals[i]:i+1}</td>
      <td class="ovt-label">${d.ev}</td>
      <td class="ovt-num" style="color:${numColor}">${d.n}</td>
    </tr>`;
  }).join('');
  document.getElementById('evChart').innerHTML=`<table class="ovt">${rows}</table>`;
}
function renderStrokeChart(){
  const data=STROKES.map(s=>{const evs=EVENTS.filter(e=>gStroke(e)===s);const n=S.athletes.reduce((sum,a)=>sum+evs.filter(e=>getBestCut(a,e)!==null).length,0);return{s,n};}).sort((a,b)=>b.n-a.n).filter(d=>d.n>0);
  if(!data.length){document.getElementById('strokeChart').innerHTML='<div style="color:var(--muted);font-size:12px;padding:8px 0;">No data</div>';return;}
  const rows=data.map((d,i)=>{
    const top=i<2;
    const medals=['🥇','🥈'];
    return `<tr class="ovt-row${top?' ovt-top':''}">
      <td class="ovt-rank">${top?medals[i]:i+1}</td>
      <td class="ovt-label">${d.s}</td>
      <td class="ovt-num">${d.n}</td>
    </tr>`;
  }).join('');
  document.getElementById('strokeChart').innerHTML=`<table class="ovt">${rows}</table>`;
}
function renderStdBarChart(){
  const data=S.standards.map(std=>{const n=S.athletes.reduce((s,a)=>s+(getStats(a).byStd[std.id]||0),0);return{std,n};}).sort((a,b)=>b.n-a.n).filter(d=>d.n>0);
  if(!data.length){document.getElementById('stdBarChart').innerHTML='<div style="color:var(--muted);font-size:12px;padding:8px 0;">No data</div>';return;}
  const rows=data.map((d,i)=>{
    const top=i<2;
    return `<tr class="ovt-row${top?' ovt-top':''}">
      <td class="ovt-rank" style="${top?'color:'+d.std.color:''}">${top?'●':i+1}</td>
      <td class="ovt-label" style="color:${d.std.color}">${d.std.name}</td>
      <td class="ovt-num" style="color:${d.std.color}">${d.n}</td>
    </tr>`;
  }).join('');
  document.getElementById('stdBarChart').innerHTML=`<table class="ovt">${rows}</table>`;
}

// ── STANDARDS TABLE ──────────────────────────────────────────
function renderStdsTable(){
  const tk=stdVG==='female'?'timesF':'timesM';
  let html='<thead><tr><th>Event</th>';
  S.standards.forEach(s=>html+=`<th style="color:${s.color}">${s.name}</th>`);
  html+='</tr></thead><tbody>';
  EVENTS.forEach(ev=>{
    if(!S.standards.some(s=>s[tk][ev]))return;
    html+=`<tr><td>${ev}</td>`;S.standards.forEach(s=>html+=`<td style="color:${s[tk][ev]?s.color:'var(--muted)'}">${s[tk][ev]||'—'}</td>`);html+='</tr>';
  });
  document.getElementById('stdsTbl').innerHTML=html+'</tbody>';
  document.getElementById('svgBtn').textContent=stdVG==='female'?'Women':'Men';
}

