function saveTimes(){
  const a=S.athletes.find(x=>x.id===editTimesId);if(!a)return;
  // Validate all entered times before saving
  const inputs=Array.from(document.querySelectorAll('#teGrid .tein'));
  const errors=validateAllTimes(inputs.filter(i=>i.value.trim()));
  if(errors.length){
    showTimeValidationErrors(errors);
    return;
  }
  // Clear any previous error highlights
  showTimeValidationErrors([]);
  inputs.forEach(i=>{const v=i.value.trim();if(v)a.times[i.dataset.ev]=v;else delete a.times[i.dataset.ev];});
  save();closeModal('mtimes');if(curPage==='profile')showProfile(editTimesId);renderRoster();
}

