// ── BACK NAVIGATION ──────────────────────────────────────────
// Track page history so back button navigates instead of exiting
const pageHistory = [];

// Override showPage to record history
const _origShowPage = showPage;
showPage = function(p) {
  // Normalise legacy page names
  const mapped = (p==='chart'||p==='standards') ? 'charts' : p==='settings' ? null : p;
  if (!mapped) return; // settings is now a modal, not a page
  if (curPage && curPage !== mapped) {
    pageHistory.push(curPage);
  }
  _origShowPage(mapped);
};

// Called by Android when back button is pressed
function handleBackPress() {
  if (pageHistory.length > 0) {
    const prev = pageHistory.pop();
    _origShowPage(prev);
    return true;
  }
  if (curPage !== 'roster') {
    _origShowPage('roster');
    return true;
  }
  return false;
}

// ── INIT ─────────────────────────────────────────────────────
loadState();
AppBridge.notifyReady();
document.getElementById('tns').textContent=S.teamName;
document.getElementById('stn').value=S.teamName;
document.getElementById('logoTN').value=S.teamName;
if(S.teamLogo)applyLogo();
// Init theme icon state
{
  const isLight=S.theme==='light';
  const iconDark=document.getElementById('themeIconDark');
  const iconLight=document.getElementById('themeIconLight');
  if(iconDark)iconDark.style.display=isLight?'none':'block';
  if(iconLight)iconLight.style.display=isLight?'block':'none';
}
renderRoster();
// Backup reminder — fires 2s after load so it doesn't block startup
